// Get raw text from "Extract from File"
let text = $json.text || "";

// Normalise whitespace
text = text.replace(/\r/g, "\n");
text = text.replace(/\n{3,}/g, "\n\n").trim();

// Optional: hard limit to prevent insane token counts
const maxChars = 25000;
if (text.length > maxChars) {
  text = text.slice(0, maxChars);
}

// We only care about the CV text here.
// File metadata is handled in Code in JavaScript2.
return {
  data: {
    cv_text: text
  }
};

// Get what the AI Agent produced.
// For the AI Agent node, the main output is usually in `output`.
let out = $json.output;

// If the model is in JSON mode (responseFormat: json_object), `out` will already be an object.
if (out && typeof out === 'object') {
  // Just wrap it as a single n8n item
  return [{ json: out }];
}

// If we get a string (e.g. JSON text), parse it.
if (typeof out === 'string') {
  let raw = out.trim();

  // Strip accidental ```json fences if they appear
  raw = raw
    .replace(/^```json/i, '')
    .replace(/^```/i, '')
    .replace(/```$/i, '')
    .trim();

  let profile;
  try {
    profile = JSON.parse(raw);
  } catch (e) {
    throw new Error(
      'Failed to parse JSON from AI Agent output: ' +
        e.message +
        '\nFirst 500 chars:\n' +
        raw.slice(0, 500)
    );
  }

  return [{ json: profile }];
}

// If neither string nor object, fail loudly so you can inspect
throw new Error('Unexpected AI Agent output type: ' + typeof out);

// Metadata from "Download file" comes in as JSON on this node
const dl = $json;

const meta = {
  file_id: dl.id || null,
  file_name: dl.name || null,
};

// Keep the binary so the Merge still works as expected
return [{
  json: meta,
  binary: $binary
}];

// Run-once classification & generic base rate calculation.

// 1. Get the parsed profile from "Code in JavaScript1"
const profileItems = $items('Code in JavaScript1');
if (!profileItems.length || !profileItems[0].json) {
  throw new Error(
    'Profile data from node "Code in JavaScript1" not found. ' +
    'Check the node name and wiring.'
  );
}
const profile = profileItems[0].json;

// 2. Get levels from "Get row(s) in sheet" (Levels tab)
const levelItems = $items('Get row(s) in sheet');
if (!levelItems.length) {
  throw new Error('No level rows received from "Get row(s) in sheet".');
}

// Map raw rows to a typed representation, normalising nulls
const rawLevels = levelItems.map(item => {
  const row = item.json;
  const id = parseInt(row.level_id, 10);

  // Handle missing min_years_dev for the lowest level by assuming 0
  let minDevRaw = row.min_years_dev;
  if ((minDevRaw === undefined || minDevRaw === '') && id === 1) {
    minDevRaw = 0;
  }

  const minDev =
    minDevRaw !== undefined && minDevRaw !== '' ? parseFloat(minDevRaw) : null;

  const maxDevRaw = row.max_years_dev;
  const minSkillRaw = row.min_years_skill;
  const maxSkillRaw = row.max_years_skill;

  return {
    level_id: id,
    label: row.label,              // optional, can be empty in sheet
    key: row.key || null,          // optional, e.g. JUNIOR / SENIOR
    min_years_dev: minDev,
    max_years_dev:
      maxDevRaw !== undefined && maxDevRaw !== '' ? parseFloat(maxDevRaw) : null,
    min_years_skill:
      minSkillRaw !== undefined && minSkillRaw !== '' ? parseFloat(minSkillRaw) : null,
    max_years_skill:
      maxSkillRaw !== undefined && maxSkillRaw !== '' ? parseFloat(maxSkillRaw) : null,
    raw: row
  };
});

// 2a. Deduplicate by level_id (keep first occurrence)
const levelMap = new Map();
for (const lvl of rawLevels) {
  if (!lvl.level_id) continue;
  if (!levelMap.has(lvl.level_id)) {
    levelMap.set(lvl.level_id, lvl);
  }
}
const levels = Array.from(levelMap.values());

// 2b. Sanity check on level ranges (only between *different* level_ids)
const sortedLevels = [...levels].sort(
  (a, b) => (a.min_years_dev ?? 0) - (b.min_years_dev ?? 0)
);

for (let i = 0; i < sortedLevels.length; i++) {
  const current = sortedLevels[i];

  if (current.min_years_dev == null) {
    throw new Error(
      `Level ${current.level_id} (${current.label || 'unnamed'}) has no min_years_dev.`
    );
  }

  if (
    current.max_years_dev != null &&
    current.max_years_dev < current.min_years_dev
  ) {
    throw new Error(
      `Level ${current.level_id} (${current.label || 'unnamed'}) has max_years_dev < min_years_dev.`
    );
  }

  if (i > 0) {
    const prev = sortedLevels[i - 1];

    // Only treat as an error if the overlap is between *different* levels
    if (
      prev.level_id !== current.level_id &&
      prev.max_years_dev != null &&
      current.min_years_dev < prev.max_years_dev
    ) {
      throw new Error(
        `Level ranges overlap or are out of order between ` +
        `Level ${prev.level_id} and Level ${current.level_id}.`
      );
    }
  }
}

// 3. Get base rates from "Get row(s) in sheet2" (Base_Rates tab)
const baseRateItems = $items('Get row(s) in sheet2');
if (!baseRateItems.length) {
  throw new Error('No base rate rows received from "Get row(s) in sheet2".');
}
const rawBaseRates = baseRateItems.map(item => {
  const row = item.json;
  return {
    level_id: parseInt(row.level_id, 10),
    level_label: row.level_label,         // optional, convenience
    currency: row.currency || 'USD',      // default if missing
    buying_min:
      row.buying_min !== undefined && row.buying_min !== ''
        ? parseFloat(row.buying_min)
        : null,
    buying_max:
      row.buying_max !== undefined && row.buying_max !== ''
        ? parseFloat(row.buying_max)
        : null,
    raw: row
  };
});

// Deduplicate base rates by level_id as well
const baseRateMap = new Map();
for (const br of rawBaseRates) {
  if (!br.level_id) continue;
  if (!baseRateMap.has(br.level_id)) {
    baseRateMap.set(br.level_id, br);
  }
}
const baseRates = Array.from(baseRateMap.values());

// 4. Get scarcity config from "Get row(s) in sheet1" (Scarcity_Factors tab)
const scarcityItems = $items('Get row(s) in sheet1') || [];

// Deduplicate by scarcity_id and normalise
const scarcityMap = new Map();
for (const item of scarcityItems) {
  const row = item.json;
  if (!row.scarcity_id) continue;
  if (!scarcityMap.has(row.scarcity_id)) {
    scarcityMap.set(row.scarcity_id, {
      scarcity_id: row.scarcity_id,
      label: row.label,
      description: row.description || '',
      factor:
        row.factor !== undefined && row.factor !== ''
          ? parseFloat(row.factor)
          : 1.0
    });
  }
}
const scarcityOptions = Array.from(scarcityMap.values());

// 5. Read years from the profile
const yearsDev = Number(profile.years_intl_dev ?? 0);
const yearsSkill = Number(profile.years_in_skill_area ?? 0);

// ---- EXPERIENCE LEVEL CLASSIFICATION ----
let baseLevel = null;

for (const lvl of levels) {
  const devOK =
    yearsDev >= (lvl.min_years_dev ?? 0) &&
    (lvl.max_years_dev == null || yearsDev <= lvl.max_years_dev);

  const skillOK =
    yearsSkill >= (lvl.min_years_skill ?? 0) &&
    (lvl.max_years_skill == null || yearsSkill <= lvl.max_years_skill);

  if (devOK && skillOK) {
    baseLevel = lvl;
  }
}

// If no exact match, fall back conservatively to the highest level
// whose min_years_dev <= yearsDev
if (!baseLevel) {
  for (const lvl of sortedLevels) {
    if (yearsDev >= (lvl.min_years_dev ?? 0)) {
      baseLevel = lvl;
    }
  }
}

// If still no match (e.g. years missing), default to lowest level
if (!baseLevel) {
  baseLevel = levels.sort(
    (a, b) => (a.level_id || 0) - (b.level_id || 0)
  )[0];
}

// Promotion: leadership / publications → +1 level (max 4 by design)
let finalLevelId = baseLevel.level_id;
const hasLead = !!profile.has_team_lead_experience;
const hasPubs = !!profile.has_publications;

if ((hasLead || hasPubs) && finalLevelId < 4) {
  finalLevelId += 1;
}

const finalLevel =
  levels.find(l => l.level_id === finalLevelId) || baseLevel;

// 6. Map level_id → stable key / label (safety net if sheet is incomplete)
const levelNameMap = {
  1: 'Junior',
  2: 'Intermediate',
  3: 'Senior',
  4: 'Expert'
};

const levelKeyMap = {
  1: 'JUNIOR',
  2: 'INTER',
  3: 'SENIOR',
  4: 'EXPERT'
};

const levelLabelFromSheet = finalLevel.raw && finalLevel.raw.label;
const levelKeyFromSheet = finalLevel.raw && finalLevel.raw.key;

const effectiveLevelLabel =
  levelLabelFromSheet || levelNameMap[finalLevelId] || `Level ${finalLevelId}`;

const effectiveLevelKey =
  levelKeyFromSheet || levelKeyMap[finalLevelId] || `LEVEL_${finalLevelId}`;

// 7. GENERIC BASE RATE BAND FOR THIS PROFILE (no project context yet)

// Find base rate row for this level
let baseRow = baseRates.find(br => br.level_id === finalLevelId);
if (!baseRow) {
  // fallback: lowest level if mismatch
  baseRow = baseRates.sort(
    (a, b) => (a.level_id || 0) - (b.level_id || 0)
  )[0];
}

const baseMin = baseRow.buying_min ?? 0;
const baseMax = baseRow.buying_max ?? baseMin;
const baseAvg = (baseMin + baseMax) / 2;

const genericRateBand = {
  currency: baseRow.currency,
  min: baseMin,
  max: baseMax,
  avg: baseAvg
};

// 8. SCARCITY OPTIONS (NOT APPLIED YET)
const scarcityFlags = {
  applied_scarcity_ids: [],  // will be set in project-specific step
  scarcity_factor: 1.0,      // neutral at generic stage
  options: scarcityOptions
};

// 9. Build final enriched profile
const enrichedProfile = {
  ...profile,
  level_id: finalLevelId,
  level_key: effectiveLevelKey,
  level_label: effectiveLevelLabel,
  level_config: finalLevel.raw,       // full row from Levels tab
  generic_rate_band: genericRateBand, // min / max / avg for this CV
  scarcity_flags: scarcityFlags,
  classification_debug: {
    base_level_id: baseLevel.level_id,
    base_level_label: baseLevel.label || levelNameMap[baseLevel.level_id],
    years_intl_dev: yearsDev,
    years_in_skill_area: yearsSkill,
    promoted_for_leadership_or_publications: hasLead || hasPubs
  }
};

// 10. Return a single item
return [{ json: enrichedProfile }];

// Profile rate tuning: from generic band (level-based) to individual band (profile-based)
// This node:
// - Starts from generic_rate_band (min/max/avg).
// - Positions the consultant within the level based on years_intl_dev.
// - Applies profile-level scarcity uplift (scarcity_ids_auto + is_economist).
// - Applies a small language uplift (modern languages only, optional niche bonus).
// - Returns an `individual_rate_band` with debug info.

// 1. Current profile object
const p = $json;

// 2. Generic band (must exist and be sensible)
const band = p.generic_rate_band || {};
const baseCurrency = band.currency || 'USD';
const baseMin = Number(band.min ?? 0);
const baseMax = Number(band.max ?? baseMin);

if (!baseMin || !baseMax || baseMax <= baseMin) {
  // If band is degenerate, just pass through without individual tuning
  return [{
    json: {
      ...p,
      individual_rate_band: null
    }
  }];
}

// 3. Position within level based on years_intl_dev vs level range

const cfg = p.level_config || {};
const levelMinDev = cfg.min_years_dev != null ? Number(cfg.min_years_dev) : null;
const levelMaxDev = cfg.max_years_dev != null ? Number(cfg.max_years_dev) : null;

// Some profiles might have `years_intn_dev` instead of `years_intl_dev`
const yearsDev = Number(
  p.years_intl_dev ??
  p.years_intn_dev ??
  0
);

let position = 0.5; // default: middle of band if we can't compute properly

if (levelMinDev != null && levelMaxDev != null && levelMaxDev > levelMinDev) {
  const span = levelMaxDev - levelMinDev;
  position = (yearsDev - levelMinDev) / span;
  if (position < 0) position = 0;
  if (position > 1) position = 1;
} else if (levelMinDev != null && levelMaxDev == null) {
  // Open-ended top level (e.g. min 15, no max):
  // assume a notional 10-year span beyond min
  const span = 10;
  position = (yearsDev - levelMinDev) / span;
  if (position < 0) position = 0;
  if (position > 1) position = 1;
}

// Base suggested point inside the generic band (before scarcity/languages)
const baseSuggested = baseMin + position * (baseMax - baseMin);

// 4. Profile-level scarcity from scarcity_ids_auto + is_economist

// Load Scarcity_Factors from "Get row(s) in sheet1"
const scarcityItems = $items('Get row(s) in sheet1') || [];
const scarcityMap = new Map();

for (const item of scarcityItems) {
  const row = item.json;
  if (!row.scarcity_id) continue;

  // profile_uplift_pct is the % uplift at profile level (e.g. 0.03 = +3%)
  const upliftRaw = row.profile_uplift_pct;
  const uplift =
    upliftRaw !== undefined && upliftRaw !== ''
      ? parseFloat(upliftRaw)
      : 0.0;

  scarcityMap.set(row.scarcity_id, {
    scarcity_id: row.scarcity_id,
    profile_uplift_pct: uplift
  });
}

// Start from auto-detected scarcity_ids (from Profile_Schema / LLM)
const autoIds = Array.isArray(p.scarcity_ids_auto) ? [...p.scarcity_ids_auto] : [];

// Map is_economist flag to ECON scarcity_id if present in config
if (p.is_economist) {
  if (!autoIds.includes('ECON')) {
    autoIds.push('ECON');
  }
}

// Sum profile uplifts from scarcity_ids_auto, with a conservative cap
let totalUplift = 0;
for (const id of autoIds) {
  const cfgRow = scarcityMap.get(id);
  if (!cfgRow) continue;
  totalUplift += cfgRow.profile_uplift_pct || 0;
}

// Cap total profile uplift from scarcity to, say, +15%
const maxProfileUplift = 0.15;
if (totalUplift > maxProfileUplift) {
  totalUplift = maxProfileUplift;
}

const scarcityFactor = 1 + totalUplift;

// 5. Language factor (modern languages only + optional niche boost)

// Normalize languages array
const langs = Array.isArray(p.languages) ? p.languages : [];

// Define a simple list of "modern/operative" languages we care about
const modernLangs = [
  'German', 'English', 'French', 'Spanish', 'Portuguese',
  'Italian', 'Dutch', 'Swedish', 'Norwegian', 'Danish',
  'Finnish', 'Polish', 'Czech', 'Slovak', 'Hungarian',
  'Romanian', 'Bulgarian', 'Greek', 'Turkish',
  'Arabic', 'Hebrew', 'Farsi', 'Urdu', 'Hindi',
  'Bengali', 'Tamil', 'Telugu', 'Kannada', 'Malayalam',
  'Russian', 'Ukrainian',
  'Chinese', 'Japanese', 'Korean',
  'Swahili', 'Amharic', 'Tigrinya', 'Somali',
  'Thai', 'Vietnamese', 'Indonesian', 'Malay'
];

// Languages we treat as "niche bonus" for profile purposes
const nicheLangs = [
  'Arabic', 'Russian', 'Pashto', 'Dari', 'Farsi',
  'Tigrinya', 'Amharic', 'Somali', 'Swahili',
  'Ukrainian', 'Hebrew'
];

let modernLangCount = 0;
let hasNiche = false;

for (const l of langs) {
  const name = (l.language || '').trim();
  if (!name) continue;

  if (modernLangs.includes(name)) {
    modernLangCount += 1;
  }
  if (nicheLangs.includes(name)) {
    hasNiche = true;
  }
}

let langFactor = 1.0;

// e.g. +2% if the consultant speaks ≥3 modern languages
if (modernLangCount >= 3) {
  langFactor += 0.02;
}

// e.g. +3% if at least one niche language
if (hasNiche) {
  langFactor += 0.03;
}

// Cap the language uplift at +5% overall
if (langFactor > 1.05) {
  langFactor = 1.05;
}

// 6. Combined profile factor (without client/project yet)

const profileFactor = scarcityFactor * langFactor;

// 7. Construct the individual band

// We narrow around baseSuggested: ±15% (before applying profileFactor)
const spread = 0.15;

let indMin = baseSuggested * (1 - spread);
let indMax = baseSuggested * (1 + spread);

// Clamp to the generic band
if (indMin < baseMin) indMin = baseMin;
if (indMax > baseMax) indMax = baseMax;

// Apply profile factor to the band and suggested point
const finalMin = indMin * profileFactor;
const finalMax = indMax * profileFactor;
const finalAvg = (finalMin + finalMax) / 2;
const finalSuggested = baseSuggested * profileFactor;

// 8. Build the result object

const individualBand = {
  currency: baseCurrency,
  min: finalMin,
  max: finalMax,
  avg: finalAvg,
  suggested: finalSuggested,
  debug: {
    base_band_min: baseMin,
    base_band_max: baseMax,
    position_within_level: position,
    scarcity_factor: scarcityFactor,
    language_factor: langFactor,
    profile_factor: profileFactor,
    auto_scarcity_ids: autoIds,
    years_intl_dev_used: yearsDev,
    level_min_years_dev: levelMinDev,
    level_max_years_dev: levelMaxDev
  }
};

// 9. Return enriched profile with individual_rate_band

return [{
  json: {
    ...p,
    individual_rate_band: individualBand
  }
}];
